375: // NamespaceRequest is used to identify a request predicated by both a revision and a namespace.
376: // This is used to identify namespaces and list resources directly beneath them (e.g. flags and segments).
377: type NamespaceRequest struct {
378: 	ReferenceRequest
379: 	key string
380: }
381: 
382: // NewNamespace constructs a *NamespaceRequest from the provided key string.
383: // Optionally, the target storage revision reference can also be supplied.
384: func NewNamespace(key string, opts ...containers.Option[ReferenceRequest]) NamespaceRequest {
385: 	p := NamespaceRequest{key: key}
386: 
387: 	containers.ApplyAll(&p.ReferenceRequest, opts...)
388: 
389: 	return p
390: }
391: 
392: // String returns the resolved target namespace key string.
393: // If the underlying key is the empty string, the default namespace ("default")
394: // is returned instead.
395: func (n NamespaceRequest) String() string {
396: 	return n.Namespace()
397: }
398: 
399: // Namespace returns the resolved target namespace key string.
400: // If the underlying key is the empty string, the default namespace ("default")
401: // is returned instead.
402: func (n NamespaceRequest) Namespace() string {
403: 	if n.key == "" {
404: 		return flipt.DefaultNamespace
405: 	}
406: 
407: 	return n.key
408: }
409: 
410: // ResourceRequest is used to identify a request predicated by revision, namespace and a key.
411: // This is used for core resources (e.g. flag and segment) as well as to list sub-resources (e.g. rules and constraints).
412: type ResourceRequest struct {
413: 	NamespaceRequest
414: 	Key string
415: }
416: 
417: // NewResource constructs and configures and new *ResourceRequest from the provided namespace and resource keys.
418: // Optionally, the target storage revision reference can also be supplied.
419: func NewResource(ns, key string, opts ...containers.Option[ReferenceRequest]) ResourceRequest {
420: 	p := ResourceRequest{
421: 		NamespaceRequest: NamespaceRequest{
422: 			key: ns,
423: 		},
424: 		Key: key,
425: 	}
426: 
427: 	containers.ApplyAll(&p.ReferenceRequest, opts...)
428: 
429: 	return p
430: }
431: 
432: // String returns a representation of the combined resource namespace and key separated by a '/'.
433: func (p ResourceRequest) String() string {
434: 	return path.Join(p.Namespace(), p.Key)
435: }
436: 
437: // IDRequest is used to identify any sub-resources which have a unique random identifier.
438: // This is used for sub-resources with no key identifiers (e.g. rules and rollouts).
439: type IDRequest struct {
440: 	ReferenceRequest
441: 	ID string
442: }
443: 
444: // NewID constructs and configures a new *IDRequest with the provided ID string.
445: // Optionally, the target storage revision reference can also be supplied.
446: func NewID(id string, opts ...containers.Option[ReferenceRequest]) IDRequest {
447: 	p := IDRequest{ID: id}
448: 	containers.ApplyAll(&p.ReferenceRequest, opts...)
449: 	return p
450: }
